import React, { useState, useEffect } from "react";
import CourseCard from "../components/CourseCard";
import SearchBar from "../components/SearchBar";
import Spinner from "../components/Spinner";
import { coursesAPI } from "../services/api";

const Home = () => {
  const [courses, setCourses] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [search, setSearch] = useState("");
  const [category, setCategory] = useState("All");
  const [level, setLevel] = useState("All");

  useEffect(() => {
    const fetchCourses = async () => {
      setLoading(true);
      setError("");
      try {
        const params = {};
        if (search) params.search = search;
        if (category !== "All") params.category = category;
        if (level !== "All") params.level = level;
        const { data } = await coursesAPI.getAll(params);
        setCourses(data);
      } catch {
        setError("Failed to load courses. Make sure the backend is running.");
      } finally {
        setLoading(false);
      }
    };
    const t = setTimeout(fetchCourses, 300);
    return () => clearTimeout(t);
  }, [search, category, level]);

  const handleSeed = async () => {
    setLoading(true);
    try {
      await coursesAPI.seed();
      const { data } = await coursesAPI.getAll({});
      setCourses(data);
      setError("");
    } catch {
      setError("Seeding failed. Please check if the backend is running.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div>
      {/* ── Hero Section ── */}
      <section style={{
        background: "linear-gradient(135deg, #0f0f1a 0%, #1a1a2e 60%, #0f0f1a 100%)",
        borderBottom: "1px solid #2a2a4a",
        padding: "80px 0 60px"
      }}>
        <div className="container">
          <div className="row align-items-center g-5">
            {/* Left text */}
            <div className="col-12 col-lg-6">
              <span className="badge mb-3 px-3 py-2" style={{
                background: "rgba(108,99,255,0.15)",
                color: "#6c63ff",
                border: "1px solid rgba(108,99,255,0.3)",
                borderRadius: 50,
                fontSize: "0.82rem",
                fontWeight: 600
              }}>
                🚀 Learn to Code
              </span>

              <h1 className="display-5 fw-bold mb-3" style={{ color: "#e8e8f0", lineHeight: 1.2 }}>
                Master{" "}
                <span style={{
                  background: "linear-gradient(135deg, #6c63ff, #43d9ad)",
                  WebkitBackgroundClip: "text",
                  WebkitTextFillColor: "transparent",
                  backgroundClip: "text"
                }}>Programming</span>
                <br />& Build Real Projects
              </h1>

              <p className="lead mb-4" style={{ color: "#9999bb", fontSize: "1.05rem" }}>
                Expert-led courses in JavaScript, Python, React, Node.js, Data Science and more.
                Level up your dev career today.
              </p>

              {/* Stats */}
              <div className="d-flex gap-4 flex-wrap">
                {[
                  { val: "10+", label: "Expert Courses" },
                  { val: "20k+", label: "Students" },
                  { val: "4.8★", label: "Avg Rating" }
                ].map((s, i) => (
                  <React.Fragment key={i}>
                    {i > 0 && <div style={{ width: 1, background: "#2a2a4a", alignSelf: "stretch" }} />}
                    <div>
                      <div className="fw-bold fs-4" style={{ color: "#e8e8f0" }}>{s.val}</div>
                      <div className="small text-uppercase" style={{ color: "#666688", letterSpacing: "0.05em" }}>{s.label}</div>
                    </div>
                  </React.Fragment>
                ))}
              </div>
            </div>

            {/* Right — code block */}
            <div className="col-12 col-lg-6">
              <div className="rounded-3 overflow-hidden shadow-lg" style={{ border: "1px solid #2a2a4a" }}>
                <div className="d-flex gap-2 align-items-center px-3 py-2" style={{ background: "#16213e", borderBottom: "1px solid #2a2a4a" }}>
                  <span style={{ width: 10, height: 10, borderRadius: "50%", background: "#ff5f56", display: "inline-block" }} />
                  <span style={{ width: 10, height: 10, borderRadius: "50%", background: "#ffbd2e", display: "inline-block" }} />
                  <span style={{ width: 10, height: 10, borderRadius: "50%", background: "#27c93f", display: "inline-block" }} />
                  <span className="ms-2 small" style={{ color: "#666688", fontFamily: "JetBrains Mono, monospace" }}>skills.js</span>
                </div>
                <pre className="m-0 p-4" style={{
                  fontFamily: "JetBrains Mono, monospace",
                  fontSize: "0.85rem",
                  color: "#43d9ad",
                  background: "#1a1a2e",
                  lineHeight: 1.8
                }}>{`const skills = [
  "JavaScript",
  "React",
  "Node.js",
  "Python",
  "MongoDB"
];

skills.forEach(skill => {
  console.log(\`✓ \${skill}\`);
});`}</pre>
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* ── Search & Filter ── */}
      <section style={{ borderBottom: "1px solid #2a2a4a" }}>
        <div className="container">
          <SearchBar
            search={search} setSearch={setSearch}
            category={category} setCategory={setCategory}
            level={level} setLevel={setLevel}
          />
        </div>
      </section>

      {/* ── Course Grid ── */}
      <section className="py-5">
        <div className="container">
          <div className="d-flex align-items-center justify-content-between mb-4">
            <h2 className="fw-bold mb-0" style={{ color: "#e8e8f0", fontSize: "1.5rem" }}>
              {search || category !== "All" || level !== "All" ? `Results (${courses.length})` : "All Courses"}
            </h2>
            {courses.length > 0 && (
              <span className="badge px-3 py-2" style={{
                background: "#1a1a2e", border: "1px solid #2a2a4a",
                color: "#9999bb", borderRadius: 50, fontWeight: 500
              }}>
                {courses.length} course{courses.length !== 1 ? "s" : ""}
              </span>
            )}
          </div>

          {loading ? (
            <Spinner message="Loading courses..." />
          ) : error ? (
            <div className="text-center py-5">
              <div className="fs-1 mb-3">⚠️</div>
              <p style={{ color: "#9999bb" }}>{error}</p>
              <button className="btn mt-2 fw-semibold" onClick={handleSeed}
                style={{ background: "#6c63ff", color: "white", border: "none", borderRadius: 8, padding: "10px 24px" }}>
                🌱 Seed Sample Courses
              </button>
            </div>
          ) : courses.length === 0 ? (
            <div className="text-center py-5">
              <div className="fs-1 mb-3">📚</div>
              <h4 style={{ color: "#e8e8f0" }}>No courses found</h4>
              <p style={{ color: "#9999bb" }}>Try adjusting your search or filters.</p>
              {!search && category === "All" && (
                <button className="btn mt-2 fw-semibold" onClick={handleSeed}
                  style={{ background: "#6c63ff", color: "white", border: "none", borderRadius: 8, padding: "10px 24px" }}>
                  🌱 Load Sample Courses
                </button>
              )}
            </div>
          ) : (
            <div className="row g-4">
              {courses.map(course => (
                <div key={course._id} className="col-12 col-sm-6 col-lg-4">
                  <CourseCard course={course} />
                </div>
              ))}
            </div>
          )}
        </div>
      </section>
    </div>
  );
};

export default Home;
